import React, { useRef } from 'react';
import { EditorProps } from '../types';
import { PRESETS } from '../constants';
import { Plus, Code2, Type, Highlighter, Quote, Heading1, Heading2, Image as ImageIcon } from 'lucide-react';

const CodeEditor: React.FC<EditorProps> = ({ value, onChange }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const insertAtCursor = (textToInsert: string) => {
    const textarea = textareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const before = text.substring(0, start);
    const after = text.substring(end, text.length);

    const newValue = before + textToInsert + after;
    onChange(newValue);

    // Reset cursor position
    setTimeout(() => {
      textarea.selectionStart = textarea.selectionEnd = start + textToInsert.length;
      textarea.focus();
    }, 0);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-r border-slate-700">
      {/* Toolbar */}
      <div className="p-4 border-b border-slate-700 bg-slate-800 flex flex-wrap gap-2">
        <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'H1 Title')?.code || '')}
          className="p-2 bg-slate-700 hover:bg-slate-600 rounded text-white transition-colors"
          title="Heading 1"
        >
          <Heading1 size={18} />
        </button>
        <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'H2 Subtitle')?.code || '')}
          className="p-2 bg-slate-700 hover:bg-slate-600 rounded text-white transition-colors"
          title="Heading 2"
        >
          <Heading2 size={18} />
        </button>
        <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'Mark')?.code || '')}
          className="p-2 bg-slate-700 hover:bg-slate-600 rounded text-white transition-colors"
          title="Highlight"
        >
          <Highlighter size={18} />
        </button>
        <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'Blockquote')?.code || '')}
          className="p-2 bg-slate-700 hover:bg-slate-600 rounded text-white transition-colors"
          title="Blockquote"
        >
          <Quote size={18} />
        </button>
        <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'Code')?.code || '')}
          className="p-2 bg-slate-700 hover:bg-slate-600 rounded text-white transition-colors"
          title="Code Block"
        >
          <Code2 size={18} />
        </button>
         <button 
          onClick={() => insertAtCursor(PRESETS.find(p => p.label === 'English Title')?.code || '')}
